mapper.select:
select 
from auction_room
where status = #{status}
  and ends_at <= #{now}
order by ends_at asc

mapper.update:
update auction_room
set current_price = #{currentPrice},
    leader_user_id = #{leaderUserId},
    leader_nickname = #{leaderNickname},
    ends_at = #{endsAt},
    status = #{status},
    version = #{version}
where room_id = #{roomId}
  and version < #{version}

update auction_room
set status = #{status}
  , version = #{version}
where room_id = #{roomId}
  and version <= #{version}
